// Expecting request body like:
// { "phone": "+91...", "message": "text" }

// In webhook executions, n8n puts JSON under $json.body
// but in the full wrapper you also see it under $json.params.body.
// We'll support both to be safe.

const body = $json.body || ($json.params && $json.params.body) || $json;

const phone = body.phone;
const message = body.message;

if (!phone || !message) {
  throw new Error('Missing phone or message in request body');
}

return {
  json: {
    phone,
    message
  }
};

// We are directly after the Postgres node.
// So $json is the row returned by Load User & Chat.

const row = $json;

const phone        = row.phone;
const userText     = row.user_message;

const userName     = row.name;
const hotelName    = row.hotel_name;
const hotelRoom    = row.hotel_room;
const hotelMap     = row.hotel_gmaps_link;
const coordName    = row.coordinator_name;
const coordPhone   = row.coordinator_phone;

const prevSummary  = row.summary || null;
const prevRecent   = row.recent_messages || [];

// System context based on summary
const systemContext = prevSummary
  ? `You are a friendly event AI assistant.\nContext: ${prevSummary}`
  : `You are a friendly event AI assistant.\nContext: First-time user.`;

// Messages array (we keep this for future tools if needed)
const messages = [
  { role: 'system', content: systemContext },
  ...prevRecent,
  { role: 'user', content: userText },
];

// Build a single prompt string for the OpenAI node
const prompt = messages
  .map(m => `${m.role.toUpperCase()}: ${m.content}`)
  .join('\n');

return {
  json: {
    phone,
    userName,
    hotelName,
    hotelRoom,
    hotelMap,
    coordName,
    coordPhone,
    prevSummary,
    prevRecent,
    userMessage: userText,
    messages,
    prompt
  }
};

// Extract AI response
const ai = $json;
const aiReply = ai.output[0].content[0].text;

// Try to parse as JSON (if AI returned structured action)
let parsed;
try {
  parsed = JSON.parse(aiReply);
} catch (e) {
  // AI returned plain text, not JSON - treat as pure chat
  return {
    json: {
      action_type: 'chat',
      reply_text: aiReply
    }
  };
}

// If AI returned JSON with action structure
return {
  json: {
    action_type: parsed.action?.type || 'chat',
    event_id: parsed.action?.event_id || null,
    reply_text: parsed.reply_text || aiReply
  }
};

const actionType = $items('Parse AI Action')[0].json.action_type;
const baseReply = $items('Parse AI Action')[0].json.reply_text;

let functionResponse;

if (actionType === 'register') {
  try {
    functionResponse = $items('Register User for Event')[0].json.register_for_event;
  } catch (e) {
    // Register branch didn't run
    functionResponse = null;
  }
} else if (actionType === 'unregister') {
  try {
    functionResponse = $items('Unregister User from Event')[0].json.unregister_from_event;
  } catch (e) {
    // Unregister branch didn't run
    functionResponse = null;
  }
}

// For now, keep reply as-is
// In Step 6, AI will interpret function results and craft responses
return {
  json: {
    finalReply: baseReply,
    functionResponse: functionResponse || null,
    actionType: actionType
  }
};

// $json is the output from Format Action Result
const item = $json;
const aiReply = item.finalReply;

// Get the context from Build LLM Messages
const ctx = $items('Build LLM Messages')[0].json;

// Previous conversation context
let recent    = ctx.prevRecent || [];
const userMsg = ctx.userMessage;

// Append the new user + assistant turn
recent.push({ role: 'user',      content: userMsg });
recent.push({ role: 'assistant', content: aiReply });

// Keep only last 3 messages
const newRecent  = recent.slice(-3);

// For now, keep previous summary as-is
const newSummary = ctx.prevSummary || null;

return {
  json: {
    phone: ctx.phone,
    summary: newSummary,
    recent_messages: newRecent,
    aiReply
  }
};
